import React, { useState } from 'react';
import { 
  Users, Flag, Settings, ShieldCheck, 
  Trash2, UserCheck, AlertTriangle, Save 
} from 'lucide-react';

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState('users');

  // Mock Data
  const [users, setUsers] = useState([
    { id: 1, name: 'Rahul K.', email: 'rahul@wertech.com', status: 'Active', role: 'User' },
    { id: 2, name: 'Gouri', email: 'gouri@wertech.com', status: 'Active', role: 'Premium' },
    { id: 3, name: 'Unknown User', email: 'spam@bot.com', status: 'Flagged', role: 'User' },
  ]);

  const stats = [
    { label: 'Total Users', value: '1,284', icon: <Users />, color: 'text-blue-600' },
    { label: 'Active Reports', value: '12', icon: <Flag />, color: 'text-red-600' },
    { label: 'System Health', value: '98%', icon: <ShieldCheck />, color: 'text-teal-600' },
  ];

  return (
    <div className="p-10 max-w-7xl mx-auto space-y-10">
      {/* HEADER */}
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter uppercase">Admin Control</h1>
          <p className="text-slate-400 font-bold uppercase text-xs tracking-widest mt-1">System Management & Oversight</p>
        </div>
        <div className="flex gap-4">
          {['users', 'reports', 'settings'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${
                activeTab === tab ? 'bg-slate-900 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-100'
              }`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      {/* STATS GRID */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-8 rounded-[35px] border border-slate-50 flex items-center gap-6 shadow-sm">
            <div className={`p-4 rounded-2xl bg-slate-50 ${stat.color}`}>{stat.icon}</div>
            <div>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{stat.label}</p>
              <p className="text-2xl font-black text-slate-800">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* MAIN CONTENT AREA */}
      <div className="bg-white rounded-[40px] p-10 border border-slate-50 shadow-sm min-h-[500px]">
        
        {/* TAB: USER MANAGEMENT */}
        {activeTab === 'users' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-black text-slate-800">User Directory</h3>
              <input placeholder="Search users..." className="px-5 py-3 bg-slate-50 rounded-xl border-none outline-none text-sm w-64" />
            </div>
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 px-4">User</th>
                  <th className="pb-4 px-4">Role</th>
                  <th className="pb-4 px-4">Status</th>
                  <th className="pb-4 px-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {users.map((u) => (
                  <tr key={u.id} className="group hover:bg-slate-50/50 transition-colors">
                    <td className="py-5 px-4">
                      <p className="font-bold text-slate-800">{u.name}</p>
                      <p className="text-xs text-slate-400">{u.email}</p>
                    </td>
                    <td className="py-5 px-4">
                      <span className="text-xs font-bold text-slate-600 bg-slate-100 px-3 py-1 rounded-lg">{u.role}</span>
                    </td>
                    <td className="py-5 px-4">
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full ${u.status === 'Flagged' ? 'bg-red-100 text-red-600' : 'bg-teal-100 text-teal-600'}`}>
                        {u.status}
                      </span>
                    </td>
                    <td className="py-5 px-4 text-right space-x-2">
                      <button className="p-2 text-slate-400 hover:text-teal-600 transition-colors"><UserCheck size={18}/></button>
                      <button className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18}/></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* TAB: REPORTS */}
        {activeTab === 'reports' && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <AlertTriangle size={48} className="text-amber-400" />
            <div className="text-center">
              <h3 className="font-black text-slate-800 text-xl">No Pending Reports</h3>
              <p className="text-slate-400 font-medium italic">Everything looks clean!</p>
            </div>
          </div>
        )}

        {/* TAB: SYSTEM SETTINGS */}
        {activeTab === 'settings' && (
          <div className="max-w-2xl space-y-8">
            <h3 className="text-xl font-black text-slate-800">General Settings</h3>
            <div className="space-y-6">
              <div className="flex justify-between items-center p-6 bg-slate-50 rounded-3xl">
                <div>
                  <p className="font-bold text-slate-800">Maintenance Mode</p>
                  <p className="text-xs text-slate-400 font-medium">Disable all trading functions for maintenance</p>
                </div>
                <div className="w-12 h-6 bg-slate-200 rounded-full relative">
                  <div className="w-4 h-4 bg-white rounded-full absolute top-1 left-1 shadow-sm" />
                </div>
              </div>
              <div className="space-y-2 px-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Base Transaction Fee (WTK)</label>
                <input type="number" defaultValue="5" className="w-full p-4 bg-slate-50 rounded-2xl border-none outline-none focus:ring-2 ring-teal-500 font-bold" />
              </div>
              <button className="flex items-center justify-center gap-3 w-full py-5 bg-teal-600 text-white rounded-[24px] font-black uppercase text-sm tracking-widest shadow-xl hover:bg-teal-700">
                Save Changes <Save size={18} />
              </button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}
